// === NAMED RANGES (defined via Name Manager or Sheets Named Ranges) ===
// Category   → Column B (B2:B200)
// Description → Column C (C2:C200)
// Budgeted   → Column D (D2:D200)
// Actual     → Column E (E2:E200)
// Variance   → Column F (F2:F200)  ← calculated

// === VARIANCE COLUMN (Column F) ===
// Simple variance: positive = under budget, negative = over budget
=D2-E2

// === STATUS COLUMN (Column G) — Nested IF ===
// Returns: "On Track", "At Risk", or "Over Budget"
=IF(F2>0, "On Track", IF(F2>=-500, "At Risk", "Over Budget"))

// === SUMMARY SHEET — SUMIF by Category ===
// Total budgeted for Design category:
=SUMIF(Category, "Design", Budgeted)

// Total actual spend for Logistics category:
=SUMIF(Category, "Logistics", Actual)

// === VLOOKUP — Retrieve supplier contact from reference table ===
// Looks up the Category in a Suppliers sheet (Sheet2!A:C)
// Returns the contact email from column 3
=VLOOKUP(B2, Sheet2!$A:$C, 3, FALSE)

// === XLOOKUP (Excel 365 / Google Sheets) — More robust alternative ===
// Advantage: no need to count column index; handles not-found gracefully
=XLOOKUP(B2, Sheet2!$A:$A, Sheet2!$C:$C, "No supplier found")

// === COUNTIF — Count how many items are Over Budget ===
=COUNTIF(G2:G200, "Over Budget")

// === CONDITIONAL FORMATTING RULE (applied to Column G) ===
// Red fill: =G2="Over Budget"
// Orange fill: =G2="At Risk"
// Green fill: =G2="On Track"

// Assume data is in a table named TicketSales with columns:
// TransactionID | Date | Category | Quantity | UnitPrice | Revenue | Postcode | DayOfWeek

// === BASIC DESCRIPTIVE STATS ===
=AVERAGE(TicketSales[Revenue])        // Mean revenue per transaction
=MEDIAN(TicketSales[Revenue])         // Median — less affected by outliers
=MAX(TicketSales[Revenue])            // Highest single transaction
=STDEV(TicketSales[Revenue])          // Standard deviation — spread of values

// === SUMIFS — Revenue by Category AND Day ===
// Total revenue for General Admission tickets on Saturday:
=SUMIFS(TicketSales[Revenue], TicketSales[Category], "General Admission", TicketSales[DayOfWeek], "Saturday")

// === COUNTIFS — Count transactions meeting multiple conditions ===
// How many VIP transactions were above $200 revenue?
=COUNTIFS(TicketSales[Category], "VIP", TicketSales[Revenue], ">200")

// === TEXT functions for data cleaning ===
// Standardise Category column:
=PROPER(TRIM(B2))   // Removes spaces AND fixes capitalisation in one step

// === WEEKDAY function — Extract day of week from date ===
// Returns 1=Sunday, 2=Monday ... 7=Saturday
=TEXT(A2, "dddd")   // Returns full day name: "Monday", "Tuesday", etc.

// === IFERROR — Prevent #N/A errors in VLOOKUP results ===
=IFERROR(VLOOKUP(A2, PostcodeRef!$A:$B, 2, FALSE), "Postcode not found")

// === LARGE / SMALL — Find top 3 postcodes by revenue ===
=LARGE(TicketSales[Revenue], 1)   // Highest revenue transaction
=LARGE(TicketSales[Revenue], 2)   // Second highest
=LARGE(TicketSales[Revenue], 3)   // Third highest
